/// Native kernel cap (mirrors `model.rs:BATCH_CAPACITY` non-wasm). Requests
/// with seq_len > this value are rejected at the wire boundary so the
/// process survives. The deployed wasm worker has cap=4; native = 8.
const NATIVE_BATCH_CAPACITY: usize = 8;
use tiny_http::{Header, Method, Request, Response, Server};

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Role {
    Entry,
    Mid,
    Exit,
    Both,
    Cobordism,
}

impl Role {
    fn parse(s: &str) -> Result<Self, String> {
        match s.to_lowercase().as_str() {
            "entry" => Ok(Role::Entry),
            "mid" => Ok(Role::Mid),
            "exit" => Ok(Role::Exit),
            "both" => Ok(Role::Both),
            "cobordism" => Ok(Role::Cobordism),
            other => Err(format!(
                "--role must be entry|mid|exit|both|cobordism (got '{}')",
                other
            )),
        }
    }
    fn as_str(self) -> &'static str {
        match self {
            Role::Entry => "entry",
            Role::Mid => "mid",
            Role::Exit => "exit",
            Role::Both => "both",
            Role::Cobordism => "cobordism",
        }
    }
}

#[derive(Debug)]
struct Cli {
    /// Required when serving a dense `.knot` (the legacy path). Optional
    /// when `--rknot` is set — only used as a basename for the standing-
    /// wave / lowrank sidecar caches in that case.
    knot: Option<String>,
    /// Resonance Knot path or URL. When set, fat-station boots from
    /// rknot + dense fallback instead of mmaping a single dense `.knot`.
    /// `--dense` is required alongside (RknotBackend serves spectral
    /// Q/K/V/FFN; the dense fallback supplies norms/biases/embeddings/
    /// lm_head — see `RknotBackend::with_dense_fallback`).
    rknot: Option<String>,
    /// Dense `.knot` source (path or http(s) URL) used as the fallback
    /// behind `--rknot`. Reuses the existing `KnotWeights::load` dispatch
    /// (`load_mmap` for local paths, `load_http` for URLs).
    dense: Option<String>,
    port: u16,
    role: Role,
    layers: (usize, usize), // [start, end)
    /// Self-settling stage election (gossip-driven, no hardcoded deployments): with
    /// `--auto-stage` + `--stages a..b,c..d` + `--seed <data-url>`, the node queries the
    /// seed's live gossip view at startup and elects the most under-replicated stage
    /// (RAM-aware) instead of taking a fixed `--role`/`--layers`. Replica coverage then
    /// settles + evolves as nodes join/leave.
    auto_stage: bool,
    stages: Vec<(usize, usize)>,
    seed: Option<String>,
    target_replicas: usize,
    /// Per-node MEMORY sharding: when set, the knot is a shard (entry/mid/exit
    /// sub-knot from `shard-knot`) and only this role's components are loaded
    /// (entry: embed + layers; exit: layers + final_norm + lm_head; mid: layers).
    /// Without it, the full knot is loaded (compute-split mode), regardless of role.
    sharded: bool,
    /// Next-stage replica pool for /chain (`--next url1,url2,...`). Empty = chain tail.
    next: Vec<String>,
    /// Gossip/discovery (component 2). `--gossip-port N` enables it; the /chain pool
    /// is then auto-populated from live next-stage peers. `--peers ip:port,...` seeds.
    gossip_port: Option<u16>,
    peers: Vec<String>,
    node_id: Option<String>,
    /// Raw hardware id (e.g. Android ANDROID_ID) for self-naming. Never gossiped: when
    /// node_id is "auto"/absent it's hashed (bitwise) into a stable pseudonymous node id.
    hwid: Option<String>,
    model_id: Option<String>,
    advertise_host: Option<String>,
    /// Component 4: per-stage qspec admission. With --admit, an entry/both node probes
    /// each discovered next-stage peer with the PARIS vector; admits it to the routing
    /// pool only if argmax == admit_expect (a corrupt/lying node can't poison the mesh).
    admit: bool,
    admit_tokens: Vec<u32>,
    admit_expect: usize,
    /// Cache-key teleport handoff (docs/R1_MESH_PROTOCOL69.md): when set, each /chain hop
    /// caches its prefill forward output keyed by the propagated prompt hash and replays
    /// it (protocol69-gated, geodesicLength:0) on an identical prefix instead of
    /// recomputing. Off by default — opt-in optimization, never touches the proven path.
    teleport_cache: bool,
    vocab: Option<(usize, usize)>,
    /// Standing-wave PCA cache. If unset, we default to
    /// `/tmp/<knot-basename>.<policy>.pca`. If the file exists at boot
    /// we load it and turn on PCA-active routing for the policy's layer
    /// set; if it doesn't exist we log and run vanilla full-precision
    /// (no auto-fit at boot — calibration is a 5-minute job, would
    /// block server startup). Use `--no-standing-wave` to bypass entirely.
    sw_pca_cache: Option<String>,
    sw_disabled: bool,
    /// Policy name (k4|k8|k12). Default k8 — empirically validated knee
    /// for top-5 ≥ 70% at 17.4% bandwidth saved on Qwen2.5-0.5B.
    sw_policy: String,
    /// Operator-side compression: path to a .lrfd sidecar (Low-Rank FFN
    /// Down) holding per-layer (a, b, k) factorizations. If unset we
    /// default to /tmp/<knot-basename>.<sw_policy>.lrfd. If present at
    /// boot, install_ffn_down_lowrank is called for each layer in the
    /// file. Mirror of the PCA cache pattern.
    lr_ffn_down_cache: Option<String>,
    /// KV-projection compression: path to a .lrkv sidecar (Low-Rank K and V)
    /// holding per-layer (a, b, k) factorizations of W_k and W_v. If
    /// unset, defaults to /tmp/<knot-basename>.kv.lrkv. If present at
    /// boot, install_attn_k_lowrank / install_attn_v_lowrank is called
    /// for each (layer, K|V) entry. Targets the 128 MiB Cloudflare Worker
    /// cap on Gemma4-31B's KV cache.
    lr_attn_kv_cache: Option<String>,
    /// HELIX columnar embed source (URL or local path to an `.hcem` file).
    /// When set, fat-station intercepts reads of `token_embd.weight` (and
    /// `output.weight` when `--tied-lm-head` is set) and serves them from
    /// the columnar row store. Non-embedding tensors pass through to the
    /// primary knot's backend. See `HELIX_COLUMNAR_EMBED_PROPOSAL.md`.
    columnar_embed: Option<String>,
    /// Force the columnar backend to also serve `output.weight` (tied
    /// lm_head). Default: read `tie_word_embeddings` from the knot
    /// metadata when available; fall back to `false` otherwise.
    tied_lm_head: bool,
    /// Optional override of the per-row LRU capacity. Default 1024 rows.
    columnar_cache_rows: Option<usize>,
    /// Opt-in greedy repetition penalty applied to the /decode-next argmax (with
    /// the prompt seeded via /embed). 1.0 = OFF = pure argmax, so the Paris
    /// quality gate is unchanged; ~1.1-1.3 breaks small-model greedy loops.
    repetition_penalty: f32,
}

fn parse_range(arg: &str, name: &str) -> Result<(usize, usize), String> {
    // accept "a..b" or "a:b". "0..0" is allowed (zero-length, meaning "no
    // layers" — used by cobordism shards which don't drive forward).
    let sep = if arg.contains("..") { ".." } else { ":" };
    let (a, b) = arg
        .split_once(sep)
        .ok_or_else(|| format!("{}: expected 'start..end' (got '{}')", name, arg))?;
    let start: usize = a
        .parse()
        .map_err(|e| format!("{}: bad start '{}': {}", name, a, e))?;
    let end: usize = b
        .parse()
        .map_err(|e| format!("{}: bad end '{}': {}", name, b, e))?;
    if end < start {
        return Err(format!(
            "{}: end must be >= start ({} < {})",
            name, end, start
        ));
    }
    Ok((start, end))
}

fn parse_cli() -> Result<Cli, String> {
    let mut args = std::env::args().skip(1);
    let mut knot: Option<String> = None;
    let mut rknot: Option<String> = None;
    let mut dense: Option<String> = None;
    let mut port: u16 = 8000;
    let mut repetition_penalty: f32 = 1.0;
    let mut role: Option<Role> = None;
    let mut layers: Option<(usize, usize)> = None;
    let mut auto_stage = false;
    let mut stages: Vec<(usize, usize)> = Vec::new();
    let mut seed: Option<String> = None;
    let mut target_replicas: usize = 2;
    let mut sharded = false;
    let mut next: Vec<String> = Vec::new();
    let mut gossip_port: Option<u16> = None;
    let mut peers: Vec<String> = Vec::new();
    let mut node_id: Option<String> = None;
    let mut hwid: Option<String> = None;
    let mut model_id: Option<String> = None;
    let mut advertise_host: Option<String> = None;
    let mut admit = false;
    let mut teleport_cache = false;
    let mut admit_tokens: Vec<u32> = vec![785, 6722, 315, 9625, 374]; // qwen "The capital of France is"
    let mut admit_expect: usize = 12095; // " Paris"
    let mut vocab: Option<(usize, usize)> = None;
    let mut sw_pca_cache: Option<String> = None;
    let mut sw_disabled = false;
    let mut sw_policy: String = "k8".to_string();
    let mut lr_ffn_down_cache: Option<String> = None;
    let mut lr_attn_kv_cache: Option<String> = None;
    let mut columnar_embed: Option<String> = None;
    let mut tied_lm_head = false;
    let mut columnar_cache_rows: Option<usize> = None;
    while let Some(a) = args.next() {
        match a.as_str() {
            "--knot" => {
                knot = Some(args.next().ok_or("--knot requires a value")?);
            }
            "--rknot" => {
                rknot = Some(args.next().ok_or("--rknot requires a value")?);
            }
            "--dense" => {
                dense = Some(args.next().ok_or("--dense requires a value")?);
            }
            "--port" => {
                let v = args.next().ok_or("--port requires a value")?;
                port = v.parse().map_err(|e| format!("--port: {}", e))?;
            }
            "--repetition-penalty" => {
                let v = args.next().ok_or("--repetition-penalty requires a value")?;
                repetition_penalty = v
                    .parse()
                    .map_err(|e| format!("--repetition-penalty: {}", e))?;
            }
            "--role" => {
                let v = args.next().ok_or("--role requires a value")?;
                role = Some(Role::parse(&v)?);
            }
            "--auto-stage" => {
                auto_stage = true;
            }
            "--stages" => {
                let v = args.next().ok_or("--stages requires a value")?;
                stages = v
                    .split(',')
                    .filter_map(|p| {
                        let (a, b) = p.trim().split_once("..")?;
                        Some((a.trim().parse().ok()?, b.trim().parse().ok()?))
                    })
                    .collect();
            }
            "--seed" => {
                seed = Some(args.next().ok_or("--seed requires a value")?);
            }
            "--target-replicas" => {
                let v = args.next().ok_or("--target-replicas requires a value")?;
                target_replicas = v.parse().map_err(|e| format!("--target-replicas: {}", e))?;
            }
            "--layers" => {
                let v = args.next().ok_or("--layers requires a value")?;
                layers = Some(parse_range(&v, "--layers")?);
            }
            "--sharded" => {
                sharded = true;
            }
            "--next" => {
                let v = args.next().ok_or("--next requires a value")?;
                next = v
                    .split(',')
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty())
                    .collect();
            }
            "--gossip-port" => {
                let v = args.next().ok_or("--gossip-port requires a value")?;
                gossip_port = Some(v.parse().map_err(|e| format!("--gossip-port: {}", e))?);
            }
            "--peers" => {
                let v = args.next().ok_or("--peers requires a value")?;
                peers = v
                    .split(',')
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty())
                    .collect();
            }
            "--node-id" => {
                node_id = Some(args.next().ok_or("--node-id requires a value")?);
            }
            "--hwid" => {
                hwid = Some(args.next().ok_or("--hwid requires a value")?);
            }
            "--model-id" => {
                model_id = Some(args.next().ok_or("--model-id requires a value")?);
            }
            "--advertise-host" => {
                advertise_host = Some(args.next().ok_or("--advertise-host requires a value")?);
            }
            "--admit" => {
                admit = true;
            }
            "--teleport-cache" => {
                teleport_cache = true;
            }
            "--admit-tokens" => {
                let v = args.next().ok_or("--admit-tokens requires a value")?;
                admit_tokens = v
                    .split(',')
                    .filter_map(|s| s.trim().parse::<u32>().ok())
                    .collect();
            }
            "--admit-expect" => {
                let v = args.next().ok_or("--admit-expect requires a value")?;
                admit_expect = v.parse().map_err(|e| format!("--admit-expect: {}", e))?;
            }
            "--vocab" => {
                let v = args.next().ok_or("--vocab requires a value")?;
                vocab = Some(parse_range(&v, "--vocab")?);
            }
            "--standing-wave-pca" => {
                sw_pca_cache = Some(args.next().ok_or("--standing-wave-pca requires a path")?);
            }
            "--no-standing-wave" => {
                sw_disabled = true;
            }
            "--standing-wave-policy" => {
                sw_policy = args
                    .next()
                    .ok_or("--standing-wave-policy requires a value (k4|k8|k12)")?;
            }
            "--ffn-down-lowrank" => {
                lr_ffn_down_cache = Some(args.next().ok_or("--ffn-down-lowrank requires a path")?);
            }
            "--attn-kv-lowrank" => {
                lr_attn_kv_cache = Some(args.next().ok_or("--attn-kv-lowrank requires a path")?);
            }
            "--columnar-embed" => {
                columnar_embed = Some(
                    args.next()
                        .ok_or("--columnar-embed requires a URL or local .hcem path")?,
                );
            }
            "--tied-lm-head" => {
                tied_lm_head = true;
            }
            "--embed-cache-rows" => {
                let v = args
                    .next()
                    .ok_or("--embed-cache-rows requires a positive integer")?;
                let n: usize = v
                    .parse()
                    .map_err(|e| format!("--embed-cache-rows: {}", e))?;
                if n == 0 {
                    return Err("--embed-cache-rows must be >= 1".to_string());
                }
                columnar_cache_rows = Some(n);
            }
            "--help" | "-h" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
    }
    // Source-of-weights validation: either --knot (legacy mmap-or-http
    // dense path) OR --rknot + --dense (Phase 4.5 spectral path with
    // dense fallback). --rknot alone is rejected because RknotBackend
    // needs the dense fallback to serve non-spectral tensors per
    // `RknotBackend::with_dense_fallback`'s contract.
    match (knot.is_some(), rknot.is_some(), dense.is_some()) {
        (true, false, false) => { /* legacy dense path */ }
        (false, true, true) => { /* spectral + dense fallback */ }
        (false, false, false) => {
            return Err(
                "must provide --knot PATH (legacy dense) OR --rknot PATH/URL --dense PATH/URL (Phase 4.5 spectral)"
                    .to_string(),
            );
        }
        (_, true, false) => {
            return Err(
                "--rknot requires --dense (RknotBackend serves spectral Q/K/V/FFN; dense fallback supplies norms/biases/embeddings/lm_head)"
                    .to_string(),
            );
        }
        (false, false, true) => {
            return Err(
                "--dense without --rknot is meaningless (use --knot for the legacy dense path)"
                    .to_string(),
            );
        }
        (true, _, _) => {
            return Err(
                "--knot is mutually exclusive with --rknot/--dense (pick one source-of-weights path)"
                    .to_string(),
            );
        }
    }
    let role = match role {
        Some(r) => r,
        // --auto-stage elects the real role/layers from gossip at startup; default until then.
        None if auto_stage => Role::Both,
        None => return Err("--role is required (or use --auto-stage)".to_string()),
    };
    if auto_stage && stages.is_empty() {
        return Err("--auto-stage requires --stages a..b,c..d".to_string());
    }
    // For cobordism shards we still ask for --layers (they don't drive the
    // pipeline but they're harmless metadata for /health).
    let layers = layers.unwrap_or((0, 0));
    if role == Role::Cobordism && vocab.is_none() {
        return Err("--vocab is required when --role=cobordism".to_string());
    }
    Ok(Cli {
        sw_pca_cache,
        sw_disabled,
        sw_policy,
        lr_ffn_down_cache,
        lr_attn_kv_cache,
        knot,
        rknot,
        dense,
        port,
        repetition_penalty,
        role,
        layers,
        auto_stage,
        stages,
        seed,
        target_replicas,
        sharded,
        next,
        gossip_port,
        peers,
        node_id,
        hwid,
        model_id,
        advertise_host,
        admit,
        admit_tokens,
        admit_expect,
        teleport_cache,
        vocab,
        columnar_embed,
        tied_lm_head,
        columnar_cache_rows,
    })
}

fn print_usage() {
    eprintln!(
        "fat-station SOURCE --port N --role {{entry|mid|exit|both|cobordism}} \\\n  \
         --layers START..END [--vocab START..END]\n  \
         [--standing-wave-pca PATH] [--standing-wave-policy k4|k8|k12] [--no-standing-wave]\n\n\
         SOURCE (one of):\n  \
         --knot PATH                       legacy dense .knot (mmap or http(s) URL)\n  \
         --rknot PATH/URL --dense PATH/URL Phase 4.5 spectral path: rknot serves\n  \
                                           Q/K/V/FFN, dense fallback supplies\n  \
                                           norms/biases/embeddings/lm_head.\n  \
                                           Multi-station Monster Mesh deploys point\n  \
                                           every fat-station at the same R2-hosted\n  \
                                           rknot URL with different --layers.\n\n\
         Roles:\n  \
         entry      serves /embed + /forward\n  \
         mid        serves /forward\n  \
         exit       serves /forward + /lm-head\n  \
         both       serves /embed + /forward + /lm-head\n  \
         cobordism  serves /cobordism-embed only (requires --vocab)\n\n\
         Standing-wave PCA cache (optional):\n  \
         If --standing-wave-pca PATH is omitted, fat-station looks for\n  \
         /tmp/<knot-basename>.<policy>.pca. If found at boot, PCA-active\n  \
         residual compression is enabled at the policy's layer set\n  \
         (k8 = top-5≥70% at 17.4% bw saved on Qwen2.5-0.5B). If not\n  \
         found, fat-station logs a warning and stays vanilla — calibration\n  \
         is a 5-min job and would block boot. Pre-fit with:\n    \
         standing-wave-pca --knot PATH --policy k8 --pca-cache PATH \\\n      \
         --cal-tokens 1..500 --test-tokens 600..615 --coverage 0.50 \\\n      \
         --all-boundaries\n  \
         In prod the cache may live in a Durable Object or R2 — fat-station\n  \
         only requires that something writes it to a local path before boot.\n\n\
         HELIX columnar embed (optional):\n  \
         --columnar-embed <URL|PATH>   serve token_embd.weight from an HCEM\n  \
                                       file (HELIX columnar embed wire format).\n                                       \
                                       URLs are range-fetched; local paths are\n                                       \
                                       mmap'd. See HELIX_COLUMNAR_EMBED_PROPOSAL.md.\n  \
         --tied-lm-head                also serve output.weight from HCEM (Qwen,\n                                       \
                                       Phi-3, Llama-3 — any model with\n                                       \
                                       tie_word_embeddings=true).\n  \
         --embed-cache-rows N          per-row LRU capacity (default 1024)."
    );
}

// ─────────────────────────────────────────────────────────────────────
// Wire helpers
// ─────────────────────────────────────────────────────────────────────

fn header_value(req: &Request, name: &str) -> Option<String> {
    let target = name.to_ascii_lowercase();
    for h in req.headers() {
        if h.field.as_str().as_str().to_ascii_lowercase() == target {
            return Some(h.value.as_str().to_string());
        }
    }
    None
}

fn parse_usize_header(req: &Request, name: &str) -> Result<usize, String> {
    let v = header_value(req, name).ok_or_else(|| format!("missing header: {}", name))?;
    v.parse::<usize>()
        .map_err(|e| format!("{}={:?}: {}", name, v, e))
}

fn parse_layer_range_header(req: &Request) -> Result<(usize, usize), String> {
    // Format: "start-end" (mirrors station.ts: `${this.startLayer}-${this.endLayer}`)
    let raw = header_value(req, "X-Layer-Range")
        .ok_or_else(|| "missing header: X-Layer-Range".to_string())?;
    let (a, b) = raw
        .split_once('-')
        .ok_or_else(|| format!("X-Layer-Range='{}': expected 'start-end'", raw))?;
    let s: usize = a
        .parse()
        .map_err(|e| format!("X-Layer-Range start: {}", e))?;
    let e: usize = b.parse().map_err(|e| format!("X-Layer-Range end: {}", e))?;
    Ok((s, e))
}

fn read_body(req: &mut Request) -> Result<Vec<u8>, String> {
    let mut buf = Vec::new();
    req.as_reader()
        .read_to_end(&mut buf)
        .map_err(|e| format!("read body: {}", e))?;
    Ok(buf)
}

fn body_to_f32(body: &[u8]) -> Result<Vec<f32>, String> {
    if body.len() % 4 != 0 {
        return Err(format!(
            "body length {} not a multiple of 4 (expected packed f32)",
            body.len()
        ));
    }
    let n = body.len() / 4;
    let mut out = vec![0.0f32; n];
    // Native LE; matches the JS Float32Array byte layout on x86/arm.
    for i in 0..n {
        let off = i * 4;
        let word = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
        out[i] = f32::from_bits(word);
    }
    Ok(out)
}

fn body_to_u32(body: &[u8]) -> Result<Vec<u32>, String> {
    if body.len() % 4 != 0 {
        return Err(format!(
            "body length {} not a multiple of 4 (expected packed u32)",
            body.len()
        ));
    }
    let n = body.len() / 4;
    let mut out = vec![0u32; n];
    for i in 0..n {
        let off = i * 4;
        out[i] = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
    }
    Ok(out)
}

fn f32_to_body(arr: &[f32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(arr.len() * 4);
    for v in arr {
        out.extend_from_slice(&v.to_bits().to_le_bytes());
    }
    out
}

fn header(name: &str, value: &str) -> Header {
    // tiny_http takes Header from a "Name: value" string — we build it from
    // parts to dodge any quirky parsing.
    Header::from_bytes(name.as_bytes(), value.as_bytes()).expect("static header bytes valid")
}

fn octet_response(
    bytes: Vec<u8>,
    request_id: &str,
    compute_ms: u128,
) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_data(bytes)
        .with_status_code(200)
        .with_header(header("Content-Type", "application/octet-stream"))
        .with_header(header("X-Request-Id", request_id))
        .with_header(header("X-Compute-Ms", &compute_ms.to_string()))
}

fn json_response(json: String, status: u16) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_string(json)
        .with_status_code(status)
        .with_header(header("Content-Type", "application/json"))
        .with_header(header("Access-Control-Allow-Origin", "*"))
        .with_header(header(
            "Access-Control-Allow-Headers",
            "Accept, Content-Type",
        ))
        .with_header(header("Access-Control-Allow-Methods", "GET, POST, OPTIONS"))
}

fn cors_preflight_response() -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_string("")
        .with_status_code(204)
        .with_header(header("Access-Control-Allow-Origin", "*"))
        .with_header(header(
            "Access-Control-Allow-Headers",
            "Accept, Content-Type",
        ))
        .with_header(header("Access-Control-Allow-Methods", "GET, POST, OPTIONS"))
}

fn error_response(msg: &str, status: u16) -> Response<std::io::Cursor<Vec<u8>>> {
    eprintln!("[fat-station] error {}: {}", status, msg);
    let body = format!("{{\"error\":{:?}}}", msg);
    json_response(body, status)
}

struct FatStationTerminalProsody {
    sentence_close_token_ids: Vec<u32>,
    stop_token_ids: Vec<u32>,
    tail_state: TerminalTailState,
}

fn parse_terminal_token_ids(value: Option<&serde_json::Value>) -> Vec<u32> {
    value
        .and_then(|v| v.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|v| v.as_u64())
                .filter(|&v| v <= u32::MAX as u64)
                .map(|v| v as u32)
                .collect()
        })
        .unwrap_or_default()
}

fn parse_terminal_tail_state(value: Option<&serde_json::Value>) -> TerminalTailState {
    match value.and_then(|v| v.as_str()) {
        Some("sentence-closed") | Some("sentence_closed") => TerminalTailState::SentenceClosed,
        _ => TerminalTailState::OpenClause,
    }
}

fn parse_terminal_prosody(json: &serde_json::Value) -> Option<FatStationTerminalProsody> {
    let config = json.get("terminal_prosody")?;
    let sentence_close_token_ids = parse_terminal_token_ids(config.get("sentence_close_token_ids"));
    let mut stop_token_ids = parse_terminal_token_ids(config.get("stop_token_ids"));
    if stop_token_ids.is_empty() {
        stop_token_ids.extend([2, 151_643]);
    }
    Some(FatStationTerminalProsody {
        sentence_close_token_ids,
        stop_token_ids,
        tail_state: parse_terminal_tail_state(config.get("tail_state")),
    })
}

// ─────────────────────────────────────────────────────────────────────
// Handlers
// ─────────────────────────────────────────────────────────────────────

// Arch-dispatching serving pipeline. Dispatches on the knot's `arch` string at
// load time: mamba|falcon-mamba→MambaPipeline, rwkv7→RWKV7Pipeline,
// gemma3|gemma4→Gemma4Pipeline, else→NativeLlamaPipeline. The non-transformer
// variants are served through the self-contained `/generate` loop only (the
// host uses /generate first on single-node deploys). Transformer-only handlers
// (chain/kv-slab/cobordism/forward-range/lm-head-range) panic via Deref on a
// non-Llama variant with a clear message; single-node gnosis-openai-<model>
// deploys never touch those routes. Deref/DerefMut to NativeLlamaPipeline keeps
// every existing transformer handler call site compiling unchanged.
enum ServingPipeline {
    Llama(NativeLlamaPipeline),
    Mamba(MambaPipeline),
    Rwkv7(RWKV7Pipeline),
    Gemma(Gemma4Pipeline),
}

impl ServingPipeline {
    fn arch_label(&self) -> &'static str {
        match self {
            ServingPipeline::Llama(_) => "transformer",
            ServingPipeline::Mamba(_) => "mamba",
            ServingPipeline::Rwkv7(_) => "rwkv7",
            ServingPipeline::Gemma(_) => "gemma",
        }
    }
    fn is_alt_arch(&self) -> bool {
        !matches!(self, ServingPipeline::Llama(_))
    }
    fn hidden_dim(&self) -> usize {
        match self {
            ServingPipeline::Llama(p) => p.hidden_dim(),
            ServingPipeline::Mamba(p) => p.config.hidden_dim,
            ServingPipeline::Rwkv7(p) => p.config.hidden_dim,
            ServingPipeline::Gemma(p) => p.config.hidden_dim,
        }
    }
    fn vocab_size(&self) -> usize {
        match self {
            ServingPipeline::Llama(p) => p.vocab_size(),
            ServingPipeline::Mamba(p) => p.config.vocab_size,
            ServingPipeline::Rwkv7(p) => p.config.vocab_size,
            ServingPipeline::Gemma(p) => p.config.vocab_size,
        }
    }
    #[allow(dead_code)]
    fn num_layers(&self) -> usize {
        match self {
            ServingPipeline::Llama(p) => p.num_layers(),
            ServingPipeline::Mamba(p) => p.config.num_layers,
            ServingPipeline::Rwkv7(p) => p.config.num_layers,
            ServingPipeline::Gemma(p) => p.config.num_layers,
        }
    }
    fn as_llama_mut(&mut self) -> Option<&mut NativeLlamaPipeline> {
        match self {
            ServingPipeline::Llama(p) => Some(p),
            _ => None,
        }
    }
    fn as_llama(&self) -> Option<&NativeLlamaPipeline> {
        match self {
            ServingPipeline::Llama(p) => Some(p),
            _ => None,
        }
    }
    /// Universal single-token forward used by `/generate`. Advances per-token
    /// recurrent / KV state at absolute `pos`; stashes next-token logits.
    fn generate_forward_one(&mut self, token: usize, pos: usize) -> Result<(), String> {
        match self {
            ServingPipeline::Llama(p) => p
                .forward_one(token, pos, false)
                .map(|_| ())
                .map_err(|e| e.to_string()),
            ServingPipeline::Mamba(p) => {
                let _ = pos;
                let vocab = p.config.vocab_size;
                MAMBA_RWKV_LOGITS.with(|cell| {
                    let mut buf = cell.borrow_mut();
                    buf.clear();
                    buf.resize(vocab, 0.0);
                    p.forward_one(token as u32, &mut buf);
                });
                Ok(())
            }
            ServingPipeline::Rwkv7(p) => {
                let _ = pos;
                let vocab = p.config.vocab_size;
                MAMBA_RWKV_LOGITS.with(|cell| {
                    let mut buf = cell.borrow_mut();
                    buf.clear();
                    buf.resize(vocab, 0.0);
                    p.forward_one(token as u32, &mut buf);
                });
                Ok(())
            }
            ServingPipeline::Gemma(p) => p.forward_one(token as u32, pos),
        }
    }
    fn logits_to(&self, out: &mut Vec<f32>) {
        match self {
            ServingPipeline::Llama(p) => {
                out.clear();
                out.extend_from_slice(p.get_logits());
            }
            ServingPipeline::Gemma(p) => {
                out.clear();
                out.extend_from_slice(p.get_logits());
            }
            ServingPipeline::Mamba(_) | ServingPipeline::Rwkv7(_) => {
                MAMBA_RWKV_LOGITS.with(|c| {
                    let cell = c.borrow();
                    out.clear();
                    out.extend_from_slice(&cell);
                });
            }
        }
    }
    fn reset_for_new_request(&mut self) {
        match self {
            ServingPipeline::Mamba(p) => p.reset_states(),
            ServingPipeline::Rwkv7(p) => p.reset_states(),
            ServingPipeline::Llama(_) | ServingPipeline::Gemma(_) => {}
        }
    }
}

// Mamba/RWKV7 forward_one writes logits into a caller buffer; we hold the last
// buffer in a thread-local so `/generate` (single-threaded per request under the
// pipeline Mutex) reads them back through `logits_to`.
thread_local! {
    static MAMBA_RWKV_LOGITS: std::cell::RefCell<Vec<f32>> =
        const { std::cell::RefCell::new(Vec::new()) };
}

impl std::ops::Deref for ServingPipeline {
    type Target = NativeLlamaPipeline;
    fn deref(&self) -> &NativeLlamaPipeline {
        match self {
            ServingPipeline::Llama(p) => p,
            other => panic!(
                "fat-station handler invoked a transformer-only pipeline method on a {} knot; \
                 use /generate for non-transformer architectures.",
                other.arch_label(),
            ),
        }
    }
}
impl std::ops::DerefMut for ServingPipeline {
    fn deref_mut(&mut self) -> &mut NativeLlamaPipeline {
        match self {
            ServingPipeline::Llama(p) => p,
            other => {
                let label = other.arch_label();
                panic!(
                    "fat-station handler invoked a transformer-only pipeline method on a {label} \
                     knot; use /generate for non-transformer architectures."
                )
            }
        }
    }
}

struct Station {
    pipeline: Mutex<ServingPipeline>,
    kv_sessions: Mutex<KvSessionStore>,
    role: Role,
    layers: (usize, usize),
    vocab: Option<(usize, usize)>,
    vocab_size: usize,
    hidden_dim: usize,
    /// Server-wide default greedy repetition penalty (from `--repetition-penalty`,
    /// 1.0 = OFF). Used by /decode-next when the request sends no X-Repetition-Penalty.
    repetition_penalty: f32,
    /// Next-stage replica POOL for /chain (from `--next url1,url2,...`). Empty = this
    /// node is the chain tail (does lm-head). Resilient routing: /chain tries these in
    /// rotated order and fails over on error, so a bricked successor doesn't wedge the
    /// mesh. See docs/R1_RESILIENT_MESH.md.
    next: Vec<String>,
    /// Gossip registry (component 2). When present, /chain derives its next-stage pool
    /// from LIVE discovered peers (dead nodes auto-evicted), falling back to `next`.
    mesh: Option<std::sync::Arc<distributed_inference::mesh_gossip::MeshRegistry>>,
    /// Protocol69 amplituhedron static-volume cache (Death #2). Standalone —
    /// independent of any loaded model knot — so /.aeon/amplituhedron-capture
    /// and /.aeon/teleport-admit work on a bare station with no weights. A
    /// cache key admitted by protocol69 (broadcast 66 xor local FOIL 7 = 69)
    /// replays a frozen amplituhedron volume LOCALLY at geodesicLength:0
    /// instead of recomputing the prefill.
    amplituhedron: Mutex<AmplituhedronCache>,
    /// Opt-in cache-key teleport handoff in /chain (docs/R1_MESH_PROTOCOL69.md): cache
    /// each prefill forward output keyed by the propagated prompt hash and replay it on
    /// an identical prefix (protocol69-gated) instead of recomputing. Off by default.
    teleport_cache: bool,
    /// DATA-plane requests in flight RIGHT NOW (the truest jam signal). Incremented
    /// per request by a drop-guard in the router so it survives handler panics; the
    /// status sampler reads it into the gossiped `NodeStatus.inflight`.
    inflight: std::sync::atomic::AtomicUsize,
    /// VLM components (ViT + adapter) — only populated when arch == "molmoact2".
    /// The LM backbone lives in `pipeline`; these provide the vision encoding half.
    vlm_vit: Option<Mutex<MolmoAct2ViT>>,
    vlm_adapter: Option<Mutex<MolmoAct2Adapter>>,
    vlm_action_expert: Option<Mutex<MolmoAct2ActionExpert>>,
}

struct ActionRun {
    action: Vec<f32>,
    cat_map_shadow: Option<CatMapShadowTelemetry>,
    cat_map_fast_path: Option<CatMapFastPathTelemetry>,
}

fn choose_cat_map_route(horizon: usize) -> Option<CertifiedCatRoute> {
    if horizon >= route_carrier_rows(CertifiedCatRoute::Mod5) {
        Some(CertifiedCatRoute::Mod5)
    } else if horizon >= route_carrier_rows(CertifiedCatRoute::Mod3) {
        Some(CertifiedCatRoute::Mod3)
    } else if horizon >= route_carrier_rows(CertifiedCatRoute::Mod2) {
        Some(CertifiedCatRoute::Mod2)
    } else {
        None
    }
}

fn parse_cat_map_route(raw: &str) -> Option<CertifiedCatRoute> {
    match raw {
        "mod5" | "5" => Some(CertifiedCatRoute::Mod5),
        "mod3" | "3" => Some(CertifiedCatRoute::Mod3),
        "mod2" | "2" => Some(CertifiedCatRoute::Mod2),
        _ => None,
    }
}

fn cat_map_route_label(route: CertifiedCatRoute) -> &'static str {
    match route {
        CertifiedCatRoute::Mod2 => "mod2",
        CertifiedCatRoute::Mod3 => "mod3",
        CertifiedCatRoute::Mod5 => "mod5",
    }
}

fn cat_map_admission_label(admission: CatMapRouteAdmission) -> &'static str {
    match admission {
        CatMapRouteAdmission::Admitted { .. } => "admitted",
        CatMapRouteAdmission::ShadowOnly { .. } => "shadow_only",
        CatMapRouteAdmission::Rejected { .. } => "rejected",
    }
}

fn cat_map_reject_reason(admission: CatMapRouteAdmission) -> Option<&'static str> {
    match admission {
        CatMapRouteAdmission::Rejected {
            reason: CatMapRouteRejectReason::EnergyIncreased,
            ..
        } => Some("energy_increased"),
        CatMapRouteAdmission::Rejected {
            reason: CatMapRouteRejectReason::TopologyRegressed,
            ..
        } => Some("topology_regressed"),
        _ => None,
    }
}

fn cat_map_shadow_json(shadow: &CatMapShadowTelemetry) -> serde_json::Value {
    let steps: Vec<serde_json::Value> = shadow
        .steps
        .iter()
        .map(|step| {
            serde_json::json!({
                "step": step.step,
                "ticks": step.ticks,
                "admission": cat_map_admission_label(step.admission),
                "rejectReason": cat_map_reject_reason(step.admission),
                "canonicalEnergy": step.evidence.canonical_energy,
                "routedEnergy": step.evidence.routed_energy,
                "topologyBefore": step.evidence.topology_before,
                "topologyAfter": step.evidence.topology_after,
                "fingerprintVerified": step.evidence.fingerprint_verified,
            })
        })
        .collect();
    serde_json::json!({
        "route": cat_map_route_label(shadow.route),
        "carrierRows": shadow.carrier_rows,
        "fingerprintVerified": shadow.fingerprint_verified,
        "steps": shadow.steps.len(),
        "admittedSteps": shadow.admitted_steps(),
        "rejectedSteps": shadow.rejected_steps(),
        "shadowOnlySteps": shadow.shadow_only_steps(),
        "stepTelemetry": steps,
    })
}

fn cat_map_fast_path_json(fast_path: &CatMapFastPathTelemetry) -> serde_json::Value {
    let steps: Vec<serde_json::Value> = fast_path
        .steps
        .iter()
        .map(|step| {
            serde_json::json!({
                "step": step.step,
                "ticks": step.ticks,
                "trajectoryEnergy": step.trajectory_energy,
                "deltaEnergy": step.delta_energy,
                "maxDelta": step.max_delta,
                "topologyDepth": step.topology_depth,
                "converged": step.converged,
            })
        })
        .collect();
    serde_json::json!({
        "route": cat_map_route_label(fast_path.route),
        "carrierRows": fast_path.carrier_rows,
        "fingerprintVerified": fast_path.fingerprint_verified,
        "configuredSteps": fast_path.configured_steps,
        "executedSteps": fast_path.executed_steps(),
        "skippedSteps": fast_path.skipped_steps(),
        "converged": fast_path.converged(),
        "convergenceEpsilon": fast_path.convergence_epsilon,
        "stepTelemetry": steps,
    })
}

fn query_value<'a>(url: &'a str, key: &str) -> Option<&'a str> {
    let query = url.split_once('?')?.1;
    for pair in query.split('&') {
        let (candidate_key, value) = pair.split_once('=').unwrap_or((pair, ""));
        if candidate_key == key {
            return Some(value);
        }
    }
    None
}

fn parse_query_usize(url: &str, keys: &[&str], default: usize) -> Result<usize, String> {
    for key in keys {
        if let Some(value) = query_value(url, key) {
            return value
                .parse::<usize>()
                .map_err(|err| format!("invalid query parameter {key}={value:?}: {err}"));
        }
    }
    Ok(default)
}

fn attention_closure_benchmark_config_from_parts(
    url: &str,
    station_hidden_dim: usize,
    station_layer_count: usize,
) -> Result<AttentionClosureBenchmarkConfig, String> {
    let default = AttentionClosureBenchmarkConfig::default();
    Ok(AttentionClosureBenchmarkConfig {
        heads: parse_query_usize(url, &["heads"], default.heads)?,
        coupling: parse_query_usize(url, &["coupling"], default.coupling)?,
        observer_resolution: parse_query_usize(
            url,
            &["observer-resolution", "observerResolution"],
            default.observer_resolution,
        )?,
        residue_threshold: parse_query_usize(
            url,
            &["residue-threshold", "residueThreshold"],
            default.residue_threshold,
        )?,
        hidden_dim: parse_query_usize(url, &["hidden-dim", "hiddenDim"], station_hidden_dim)?,
        batch_size: parse_query_usize(url, &["batch-size", "batchSize"], default.batch_size)?,
        layer_count: parse_query_usize(url, &["layers", "layerCount"], station_layer_count)?,
        standing_count: parse_query_usize(
            url,
            &["standing-count", "standingCount"],
            default.standing_count,
        )?,
        requested_speculative_depth: parse_query_usize(
            url,
            &["spec-depth", "specDepth", "requestedSpeculativeDepth"],
            default.requested_speculative_depth,
        )?,
        speculative_candidates: parse_query_usize(
            url,
            &["spec-candidates", "specCandidates"],
            default.speculative_candidates,
        )?,
        head_prune_candidates: parse_query_usize(
            url,
            &["head-prune-candidates", "headPruneCandidates"],
            default.head_prune_candidates,
        )?,
        head_dim: parse_query_usize(url, &["head-dim", "headDim"], default.head_dim)?,
    })
}

fn attention_closure_benchmark_config_from_url(
    url: &str,
    station: &Station,
) -> Result<AttentionClosureBenchmarkConfig, String> {
    let station_layer_count = station.layers.1.saturating_sub(station.layers.0).max(1);
    attention_closure_benchmark_config_from_parts(url, station.hidden_dim, station_layer_count)
}

struct KvSession {
    prefix_len: usize,
    layer_lo: usize,
    layer_hi: usize,
    slab: Vec<f32>,
    updated_at_ms: u128,
}

struct KvSessionStore {
    capacity: usize,
    sessions: HashMap<String, KvSession>,
}

impl KvSessionStore {
    fn new() -> Self {
        let capacity = std::env::var("MOONSHINE_KV_SESSION_CAPACITY")
            .ok()
            .and_then(|v| v.parse::<usize>().ok())
            .filter(|&v| v > 0)
            .unwrap_or(1);
        Self {
            capacity,
            sessions: HashMap::new(),
        }
    }

    fn insert(&mut self, id: String, session: KvSession) {
        if !self.sessions.contains_key(&id) && self.sessions.len() >= self.capacity {
            if let Some(oldest_id) = self
                .sessions
                .iter()
                .min_by_key(|(_, session)| session.updated_at_ms)
                .map(|(id, _)| id.clone())
            {
                self.sessions.remove(&oldest_id);
            }
        }
        self.sessions.insert(id, session);
    }
}

/// /mesh/peers — inspect the gossip registry: this node, live discovered peers, and
/// the current next-stage failover pool. (Component 2 observability.)
fn handle_mesh_peers(station: &Station, req: Request) {
    let body = match &station.mesh {
        Some(reg) => serde_json::to_string(&serde_json::json!({
            "self": reg.self_info(),
            "live_peers": reg.live_peers(),
            "next_stage_pool": reg.next_stage_pool(),
        }))
        .unwrap_or_else(|_| "{}".to_string()),
        None => "{\"mesh\":\"disabled\"}".to_string(),
    };
    // json_response carries CORS (Access-Control-Allow-Origin: *) so a browser dashboard
    // can read the whole fleet from one node (auto-discovery + edge topology).
    let _ = req.respond(json_response(body, 200));
}

/// /mesh/hive — the 2002 (brain) yield: a FOLD FlowFrame carrying the "what's up"
/// digest (node count, stage coverage, health), so the hive stays aware without the
/// raw 2010 heartbeats. Body = the raw 2002 FlowFrame bytes; X-Mesh-Status header
/// carries the one-line verdict for quick reads.
fn handle_mesh_hive(station: &Station, req: Request) {
    match &station.mesh {
        Some(reg) => {
            let status = reg.mesh_summary().status;
            let frame = reg.hive_frame();
            let resp = Response::from_data(frame)
                .with_header(
                    Header::from_bytes(&b"Content-Type"[..], &b"application/octet-stream"[..])
                        .unwrap(),
                )
                .with_header(Header::from_bytes(&b"X-Stream-Id"[..], &b"2002"[..]).unwrap())
                .with_header(
                    Header::from_bytes(&b"X-Mesh-Status"[..], status.as_bytes()).unwrap_or_else(
                        |_| Header::from_bytes(&b"X-Mesh-Status"[..], &b"?"[..]).unwrap(),
                    ),
                )
                // CORS so a browser dashboard can read the digest + the verdict header.
                .with_header(
                    Header::from_bytes(&b"Access-Control-Allow-Origin"[..], &b"*"[..]).unwrap(),
                )
                .with_header(
                    Header::from_bytes(
                        &b"Access-Control-Expose-Headers"[..],
                        &b"X-Mesh-Status, X-Stream-Id"[..],
                    )
                    .unwrap(),
                );
            let _ = req.respond(resp);
        }
        None => {
            let _ = req.respond(error_response("mesh disabled (no --gossip-port)", 404));
        }
    }
}

fn handle_health(station: &Station, req: Request) {
    let layers = format!("{}-{}", station.layers.0, station.layers.1);
    let vocab = match station.vocab {
        Some((s, e)) => format!("{}-{}", s, e),
        None => "all".to_string(),
    };
    let (
        ffn_leakage_mode,
        ffn_leakage_mode_semantics,
        ffn_guard_admit_weather_cells,
        ffn_guard_speculate_weather_cells,
        ffn_guard_deny_weather_cells,
        ffn_predictive_min_gate_up_skip_blocks,
        ffn_guard_min_logit_margin,
        ffn_guard_high_confidence_logit_margin,
        ffn_guard_rms_delta3_threshold,
    ) = {
        let p = station.pipeline.lock().unwrap();
        // FFN-leakage / weather-cell guards are NativeLlamaPipeline-only; report
        // defaults for alt archs so /health never panics via the Deref bridge.
        match p.as_llama() {
            Some(llama) => (
                llama.ffn_leakage_mode_label(),
                llama.ffn_leakage_mode_semantics().to_string(),
                llama.ffn_guard_admit_weather_cells_label(),
                llama.ffn_guard_speculate_weather_cells_label(),
                llama.ffn_guard_deny_weather_cells_label(),
                llama.ffn_predictive_min_gate_up_skip_blocks(),
                llama.ffn_guard_min_logit_margin(),
                llama.ffn_guard_high_confidence_logit_margin(),
                llama.ffn_guard_rms_delta3_threshold(),
            ),
            None => (
                "off".to_string(),
                "disabled".to_string(),
                guarded_mirror_weather_cell_label(0, 0, 0, 0),
                guarded_mirror_weather_cell_label(0, 0, 0, 0),
                guarded_mirror_weather_cell_label(0, 0, 0, 0),
                predictive_gate_up_min_skip_blocks(),
                guarded_mirror_min_logit_margin(),
                guarded_mirror_high_confidence_logit_margin(),
                guarded_mirror_max_rms_delta3_tail(),
            ),
        }
    };
    let body = serde_json::json!({
        "status": "ok",
        "role": station.role.as_str(),
        "layers": layers,
        "vocab": vocab,
        "vocab_size": station.vocab_size,
        "hidden_dim": station.hidden_dim,
        // Capability flags so the openai-server host can gate KV-reuse paths
        // (liquid memory) without an active probe. A binary that lacks the
        // /kv-session routes would not even reach this code, so reporting `true`
        // here is the truthful self-description for any build that serves
        // /health from this handler. See LIQUID_MEMORY_KV_SAVE.md.
        "kv_session": true,
        "decode_next": true,
        "ffn_leakage_mode": ffn_leakage_mode.as_str(),
        "ffn_leakage_mode_default": ffn_leakage_mode.as_str(),
        "ffn_leakage_mode_semantics": ffn_leakage_mode_semantics.as_str(),
        "interference_anchor": FFN_INTERFERENCE_ANCHOR_COORDINATE,
        "interference_closure": FFN_INTERFERENCE_CLOSURE_COORDINATE,
        "interference_closure_stride": FFN_INTERFERENCE_CLOSURE_STRIDE,
        "pressure_weighted_interference_total": FFN_PRESSURE_WEIGHTED_INTERFERENCE_TOTAL,
        "ffn_input_pressure_skipped_blocks": 0,
        "ffn_hidden_pressure_skipped_blocks": 0,
        "ffn_skipped_blocks": 0,
        "ffn_guard_fallbacks": 0,
        "ffn_guard_sieve_pre_rejects": 0,
        "ffn_guard_rms_delta3_threshold": ffn_guard_rms_delta3_threshold,
        "ffn_guard_rms_delta3_threshold_default": guarded_mirror_max_rms_delta3_tail(),
        "ffn_guard_min_logit_margin": ffn_guard_min_logit_margin,
        "ffn_guard_min_logit_margin_default": guarded_mirror_min_logit_margin(),
        "ffn_guard_high_confidence_logit_margin": ffn_guard_high_confidence_logit_margin,
        "ffn_guard_high_confidence_logit_margin_default": guarded_mirror_high_confidence_logit_margin(),
        "ffn_predictive_min_gate_up_skip_blocks": ffn_predictive_min_gate_up_skip_blocks,
        "ffn_predictive_min_gate_up_skip_blocks_default": predictive_gate_up_min_skip_blocks(),
        "ffn_guard_admit_weather_cells": ffn_guard_admit_weather_cells.as_str(),
        "ffn_guard_speculate_weather_cells": ffn_guard_speculate_weather_cells.as_str(),
        "ffn_guard_deny_weather_cells": ffn_guard_deny_weather_cells.as_str(),
        "ffn_guard_weather_cell": 0,
        "ffn_guard_weather_cell_label": guarded_mirror_weather_cell_label(0, 0, 0, 0),
        "ffn_guard_weather_cell_admitted": 0,
        "ffn_guard_weather_cell_speculated": 0,
        "ffn_guard_weather_cell_denied": 0,
        "ffn_guard_weather_position_band": 0,
        "ffn_guard_weather_position_band_label": guarded_mirror_weather_position_band_label(0),
        "ffn_guard_weather_margin_band": 0,
        "ffn_guard_weather_margin_band_label": guarded_mirror_weather_margin_band_label(0),
        "ffn_guard_weather_drift_band": 0,
        "ffn_guard_weather_drift_band_label": guarded_mirror_weather_drift_band_label(0),
        "ffn_guard_weather_block_band": 0,
        "ffn_guard_weather_block_band_label": guarded_mirror_weather_block_band_label(0),
        "ffn_guard_candidate_skipped_blocks": 0,
        "ffn_hidden_pressure_mirrored_blocks": 0,
        "ffn_predictive_gate_up_skipped_blocks": 0,
        "ffn_mirror_scale": 0.0,
        "ffn_mirror_layers": 0,
        "ffn_mirror_threshold": 0,
    })
    .to_string();
    let _ = req.respond(json_response(body, 200));
}

fn handle_attention_closure_benchmark(station: &Station, req: Request) {
    let config = match attention_closure_benchmark_config_from_url(req.url(), station) {
        Ok(config) => config,
        Err(err) => {
            let _ = req.respond(error_response(&err, 400));
            return;
        }
    };
    match attention_closure_benchmark_json_pretty(config) {
        Ok(body) => {
            let _ = req.respond(json_response(body, 200));
        }
        Err(err) => {
            let _ = req.respond(error_response(
                &format!("attention closure benchmark JSON: {err}"),
                500,
            ));
        }
    }
}

