fn pressure_mean_spa(sum_spa: u64, blocks: u32) -> u64 {
    if blocks == 0 {
        0
    } else {
        sum_spa / blocks as u64
    }
}

fn residual_norm_mean(sum: f32, count: u32) -> f32 {
    if count == 0 {
        0.0
    } else {
        sum / count as f32
    }
}

fn ffn_guard_mirror_reject_reason_label(mask: u32) -> String {
    if mask == 0 {
        return "accepted".to_string();
    }
    let mut labels = Vec::new();
    if mask & FFN_GUARDED_MIRROR_REJECT_POSITION_ZERO != 0 {
        labels.push("position-zero");
    }
    if mask & FFN_GUARDED_MIRROR_REJECT_LOW_MARGIN != 0 {
        labels.push("low-margin");
    }
    if mask & FFN_GUARDED_MIRROR_REJECT_HIGH_BLOCKS != 0 {
        labels.push("high-blocks");
    }
    if mask & FFN_GUARDED_MIRROR_REJECT_HIGH_DRIFT != 0 {
        labels.push("high-drift");
    }
    if mask & FFN_GUARDED_MIRROR_REJECT_EXPLICIT_DENY != 0 {
        labels.push("explicit-deny");
    }
    if labels.is_empty() {
        labels.push("unknown");
    }
    labels.join("|")
}

fn ffn_leakage_mode_label(code: u32) -> String {
    match code {
        0 => "off".to_string(),
        1 => "observe".to_string(),
        10_001..=19_999 => format!("mask-input-low-{}", code - 10_000),
        20_001..=29_999 => format!("mask-hidden-low-{}", code - 20_000),
        30_001..=39_999 => {
            let tail_code = code - 30_000;
            let layers = tail_code / 1_000;
            let threshold = tail_code % 1_000;
            if layers <= 1 {
                format!("mask-tail-low-{threshold}")
            } else {
                format!("mask-tail{layers}-low-{threshold}")
            }
        }
        40_001..=49_999 => {
            let tail_code = code - 40_000;
            let layers = tail_code / 1_000;
            let threshold = tail_code % 1_000;
            if layers <= 1 {
                format!("guard-tail-low-{threshold}")
            } else {
                format!("guard-tail{layers}-low-{threshold}")
            }
        }
        50_001..=59_999 => {
            let tail_code = code - 50_000;
            let layers = tail_code / 1_000;
            let threshold = tail_code % 1_000;
            if layers <= 1 {
                format!("experimental-mirror-tail-low-{threshold}")
            } else {
                format!("experimental-mirror-tail{layers}-low-{threshold}")
            }
        }
        60_001..=69_999 => {
            let tail_code = code - 60_000;
            let layers = tail_code / 1_000;
            let threshold = tail_code % 1_000;
            if layers <= 1 {
                format!("guard-mirror-tail-low-{threshold}")
            } else {
                format!("guard-mirror-tail{layers}-low-{threshold}")
            }
        }
        70_001..=79_999 => {
            let tail_code = code - 70_000;
            let layers = tail_code / 1_000;
            let threshold = tail_code % 1_000;
            if layers <= 1 {
                format!("experimental-predictive-mirror-tail-low-{threshold}")
            } else {
                format!("experimental-predictive-mirror-tail{layers}-low-{threshold}")
            }
        }
        80_001..=89_999 => {
            let tail_code = code - 80_000;
            let layers = tail_code / 1_000;
            let threshold = tail_code % 1_000;
            if layers <= 1 {
                format!("guard-predictive-mirror-tail-low-{threshold}")
            } else {
                format!("guard-predictive-mirror-tail{layers}-low-{threshold}")
            }
        }
        other => format!("mask-low-{other}"),
    }
}

fn handle_cobordism_embed(station: &Station, mut req: Request) {
    if station.role != Role::Cobordism {
        let _ = req.respond(error_response(
            "/cobordism-embed only available on cobordism role",
            404,
        ));
        return;
    }
    let request_id = header_value(&req, "X-Request-Id").unwrap_or_else(|| "no-id".to_string());
    let start_pos = match parse_usize_header(&req, "X-Position") {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    // The TS client sends X-Vocab-Start / X-Vocab-End (see station.ts:531).
    // The server falls back to the bind-time --vocab if either header is absent
    // so a misconfigured client doesn't degrade silently to the wrong slice.
    let vstart = match header_value(&req, "X-Vocab-Start") {
        Some(v) => v.parse::<usize>().unwrap_or(station.vocab.unwrap().0),
        None => station.vocab.unwrap().0,
    };
    let vend = match header_value(&req, "X-Vocab-End") {
        Some(v) => v.parse::<usize>().unwrap_or(station.vocab.unwrap().1),
        None => station.vocab.unwrap().1,
    };
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let tokens = match body_to_u32(&body) {
        Ok(t) => t,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.embed_chunk_range(&tokens, start_pos, vstart, vend)
        }))
    };
    match result {
        Ok(Ok(out)) => {
            eprintln!(
                "[fat-station] /cobordism-embed tokens={} vocab=[{},{}) -> {}f32 in {} ms",
                tokens.len(),
                vstart,
                vend,
                out.len(),
                t0.elapsed().as_millis()
            );
            let _ = req.respond(octet_response(
                f32_to_body(&out),
                &request_id,
                t0.elapsed().as_millis(),
            ));
        }
        Ok(Err(e)) => {
            let _ = req.respond(error_response(
                &format!("cobordism_embed error: {}", e),
                500,
            ));
        }
        Err(e) => {
            let _ = req.respond(error_response(
                &format!("cobordism_embed panicked: {:?}", panic_payload(&e)),
                500,
            ));
        }
    }
}

